/**
 * @summary Upload and process a file
 */
export const getImportFileUrl = () => {
  return `/api/import`;
};

export const importFile = async (
  importFileBody: ImportFileBody,
  options?: RequestInit,
): Promise<ImportResult> => {
  const formData = new FormData();
  formData.append(`file`, importFileBody.file);
  formData.append(`type`, importFileBody.type);
  if (importFileBody.groupeId !== undefined) {
    formData.append(`groupeId`, importFileBody.groupeId);
  }

  return customFetch<ImportResult>(getImportFileUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

export const getImportFileMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof importFile>>,
    TError,
    { data: BodyType<ImportFileBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof importFile>>,
  TError,
  { data: BodyType<ImportFileBody> },
  TContext
> => {
  const mutationKey = ["importFile"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof importFile>>,
    { data: BodyType<ImportFileBody> }
  > = (props) => {
    const { data } = props ?? {};

    return importFile(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type ImportFileMutationResult = NonNullable<
  Awaited<ReturnType<typeof importFile>>
>;
export type ImportFileMutationBody = BodyType<ImportFileBody>;
export type ImportFileMutationError = ErrorType<unknown>;

/**
 * @summary Upload and process a file
 */
export const useImportFile = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof importFile>>,
    TError,
    { data: BodyType<ImportFileBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof importFile>>,
  TError,
  { data: BodyType<ImportFileBody> },
  TContext
> => {
  return useMutation(getImportFileMutationOptions(options));
};

